#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int freq[101]; memset(freq,0,sizeof(freq));
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            freq[x]++;
        }
        int O=0;
        for(int i=1;i<=100;i++) if(freq[i]%2) O++;
        int added = O + (((N+O)%4)==0 ? 0 : 2);
        printf("%d\n", added);
    }
    return 0;
}

